import{b as e,a as o,_ as i}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o as s,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Gerenciamento de autenticação e dispositivos conectados","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Safety/authentication-and-login-devices.md","filePath":"pt-BR/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),n={name:"pt-BR/Safety/authentication-and-login-devices.md"};function c(l,a,u,p,m,h){return s(),d("div",null,[...a[0]||(a[0]=[r('<h1 id="gerenciamento-de-autenticacao-e-dispositivos-conectados" tabindex="-1">Gerenciamento de autenticação e dispositivos conectados <a class="header-anchor" href="#gerenciamento-de-autenticacao-e-dispositivos-conectados" aria-label="Permalink to &quot;Gerenciamento de autenticação e dispositivos conectados&quot;">​</a></h1><p>O gerenciamento de autenticação permite revisar logins, sessões ativas e dispositivos conectados ao painel ou às páginas de usuário.</p><h2 id="login-de-administrador" tabindex="-1">Login de administrador <a class="header-anchor" href="#login-de-administrador" aria-label="Permalink to &quot;Login de administrador&quot;">​</a></h2><p>O administrador entra pela tela de login do painel para gerenciar arquivos e configurações.</p><p><img src="'+e+'" alt="Login de administrador" loading="lazy"></p><p>A conta administradora tem permissões altas. Mantenha as credenciais bem protegidas.</p><h2 id="login-de-usuario" tabindex="-1">Login de usuário <a class="header-anchor" href="#login-de-usuario" aria-label="Permalink to &quot;Login de usuário&quot;">​</a></h2><p>Também existe uma tela de login para usuários.</p><p><img src="'+o+'" alt="Login de usuário" loading="lazy"></p><p>Se você usa upload público ou acesso limitado, o login de usuário ajuda a saber quem realizou cada ação.</p><h2 id="tela-de-autenticacao" tabindex="-1">Tela de autenticação <a class="header-anchor" href="#tela-de-autenticacao" aria-label="Permalink to &quot;Tela de autenticação&quot;">​</a></h2><p>A tela de gerenciamento mostra sessões e dispositivos conectados.</p><p><img src="'+i+'" alt="Gerenciamento de autenticação" loading="lazy"></p><h2 id="o-que-revisar-nos-dispositivos" tabindex="-1">O que revisar nos dispositivos <a class="header-anchor" href="#o-que-revisar-nos-dispositivos" aria-label="Permalink to &quot;O que revisar nos dispositivos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Descrição</th></tr></thead><tbody><tr><td>Dispositivo conectado</td><td>Dispositivos com sessão ativa</td></tr><tr><td>IP / localização</td><td>Referência da origem do acesso</td></tr><tr><td>Último acesso</td><td>Indica se o dispositivo ainda está em uso</td></tr><tr><td>Revogar</td><td>Encerra sessões antigas ou suspeitas</td></tr></tbody></table><h2 id="se-notar-algo-suspeito" tabindex="-1">Se notar algo suspeito <a class="header-anchor" href="#se-notar-algo-suspeito" aria-label="Permalink to &quot;Se notar algo suspeito&quot;">​</a></h2><ol><li>Revogue a sessão do dispositivo.</li><li>Troque senha de administrador e tokens relacionados.</li><li>Revise credenciais da Cloudflare, GitHub e canais de armazenamento.</li><li>Gere novos API Tokens se necessário.</li></ol><h2 id="dicas-de-operacao" tabindex="-1">Dicas de operação <a class="header-anchor" href="#dicas-de-operacao" aria-label="Permalink to &quot;Dicas de operação&quot;">​</a></h2><ul><li>Não deixe sessões abertas em computadores compartilhados.</li><li>Mantenha poucas contas com permissões de administrador.</li><li>Revise periodicamente os dispositivos conectados.</li><li>Remova sessões antigas ou desconhecidas.</li></ul>',19)])])}const b=t(n,[["render",c]]);export{_ as __pageData,b as default};
